import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import axios from "axios";

function Dashboard() {

    const [stats, setStats] = useState({
        properties: 0,
        tenants: 0,
        agreements: 0,
        payments: 0
    });

    useEffect(() => {
        fetchStats();
    }, []);

    const fetchStats = async () => {

        try {

            const token = localStorage.getItem("token");

            const response = await axios.get(
                "https://rental-management-system-backend-0h42.onrender.com/dashboard/stats",
                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }
            );

            setStats(response.data);

        } catch (error) {
            console.error(error);
        }
    };

    return (
        <div className="container mt-5">

            <h1>Rental Management Dashboard</h1>

            <hr />

            {/* Statistics Cards */}
            <div className="row mb-4">

                <div className="col-md-3">
                    <div className="card bg-primary text-white">
                        <div className="card-body">
                            <h5>Properties</h5>
                            <h2>{stats.properties}</h2>
                        </div>
                    </div>
                </div>

                <div className="col-md-3">
                    <div className="card bg-success text-white">
                        <div className="card-body">
                            <h5>Tenants</h5>
                            <h2>{stats.tenants}</h2>
                        </div>
                    </div>
                </div>

                <div className="col-md-3">
                    <div className="card bg-warning text-dark">
                        <div className="card-body">
                            <h5>Agreements</h5>
                            <h2>{stats.agreements}</h2>
                        </div>
                    </div>
                </div>

                <div className="col-md-3">
                    <div className="card bg-info text-white">
                        <div className="card-body">
                            <h5>Payments</h5>
                            <h2>{stats.payments}</h2>
                        </div>
                    </div>
                </div>

            </div>

            {/* Navigation Buttons */}
            <div className="d-grid gap-3">

                <Link to="/properties" className="btn btn-primary">
                    Manage Properties
                </Link>

                <Link to="/tenants" className="btn btn-success">
                    Manage Tenants
                </Link>

                <Link to="/agreements" className="btn btn-warning">
                    Manage Agreements
                </Link>

                <Link to="/payments" className="btn btn-info">
                    Manage Payments
                </Link>

                <Link to="/blockchain" className="btn btn-dark">
                    Blockchain Verification
                </Link>

                <Link to="/audit" className="btn btn-secondary">
                    Audit Logs
                </Link>

            </div>

        </div>
    );
}

export default Dashboard;
